import{c as e,Q as d,j as o,m as r}from"./chunks/framework.BBA2dIOt.js";const p=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md","lastUpdated":1779825386000}'),a={name:"configuration.md"};function c(s,t,n,i,l,h){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>Ember reads configuration from environment variables at startup. A handful of settings can also be changed at runtime via the admin UI and persist in the <code>app_settings</code> table.</p><h2 id="required-env-vars" tabindex="-1">Required env vars <a class="header-anchor" href="#required-env-vars" aria-label="Permalink to &quot;Required env vars&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Var</th><th>Description</th></tr></thead><tbody><tr><td><code>EMBER_SESSION_KEY</code></td><td>securecookie key, 32+ random bytes. Generate via <code>openssl rand -base64 48</code>.</td></tr><tr><td><code>EMBER_ADMIN_PASSWORD</code></td><td>First-run admin password. Used only when the <code>users</code> table is empty; change via Settings → Profile after first login.</td></tr></tbody></table><h2 id="optional-env-vars" tabindex="-1">Optional env vars <a class="header-anchor" href="#optional-env-vars" aria-label="Permalink to &quot;Optional env vars&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Var</th><th>Default</th><th>Notes</th></tr></thead><tbody><tr><td><code>EMBER_ADDR</code></td><td><code>:8080</code></td><td>Bind address.</td></tr><tr><td><code>EMBER_DB_PATH</code></td><td><code>/data/ember.db</code></td><td>SQLite file path.</td></tr><tr><td><code>EMBER_ADMIN_USER</code></td><td><code>admin</code></td><td>First-run admin username.</td></tr><tr><td><code>EMBER_OLLAMA_URL</code></td><td><code>http://ollama:11434</code></td><td>Ollama API endpoint.</td></tr><tr><td><code>EMBER_OLLAMA_MODEL</code></td><td><code>qwen2.5:0.5b</code></td><td>Initial active model. The admin UI can swap to any pulled model live.</td></tr><tr><td><code>EMBER_DISABLE_SUMMARIES</code></td><td><code>0</code></td><td>Skip LLM summarization entirely. Articles still surface (poller stamps <code>summary_model=&#39;disabled&#39;</code>).</td></tr><tr><td><code>EMBER_DISABLE_IMAGES</code></td><td><code>0</code></td><td>Drop article hero images at ingest.</td></tr><tr><td><code>EMBER_ALLOW_PRIVATE_URLS</code></td><td><code>0</code></td><td>Bypass the SSRF block so feeds on RFC1918 / loopback addresses can be subscribed. <strong>Only set this if you trust every user who can add feeds.</strong></td></tr><tr><td><code>EMBER_PUBLIC_URL</code></td><td>—</td><td>Canonical <code>scheme://host</code> users hit, e.g. <code>https://reader.example.com</code>. Required to enable passkey / WebAuthn sign-in.</td></tr><tr><td><code>EMBER_SMTP_HOST</code></td><td>—</td><td>SMTP server hostname. Required to enable the daily-digest email feature.</td></tr><tr><td><code>EMBER_SMTP_PORT</code></td><td><code>587</code></td><td>SMTP port.</td></tr><tr><td><code>EMBER_SMTP_USER</code></td><td>—</td><td>SMTP auth username (optional; omit for relays without auth).</td></tr><tr><td><code>EMBER_SMTP_PASSWORD</code></td><td>—</td><td>SMTP auth password.</td></tr><tr><td><code>EMBER_SMTP_FROM</code></td><td>—</td><td><code>From:</code> address used on digest emails.</td></tr><tr><td><code>EMBER_SMTP_STARTTLS</code></td><td><code>1</code></td><td>STARTTLS on submission ports (587). Set <code>0</code> only when targeting a server that doesn&#39;t support it.</td></tr><tr><td><code>EMBER_FRESH_WINDOW</code></td><td><code>6h</code></td><td>How recent an article must be to appear in the &quot;Fresh&quot; smart view.</td></tr><tr><td><code>EMBER_POLL_CONCURRENCY</code></td><td><code>8</code></td><td>Number of feed-fetch worker goroutines.</td></tr><tr><td><code>EMBER_POLL_TICK</code></td><td><code>60s</code></td><td>How often the poller scans for feeds due to fetch.</td></tr><tr><td><code>EMBER_LOG_LEVEL</code></td><td><code>info</code></td><td><code>debug</code> / <code>info</code> / <code>warn</code> / <code>error</code>.</td></tr><tr><td><code>EMBER_TEST_MODE</code></td><td><code>0</code></td><td>Seeds fake admin + articles; loosens cookie Secure flag. Don&#39;t enable in production.</td></tr></tbody></table><h2 id="runtime-settings-persist-across-restarts" tabindex="-1">Runtime settings (persist across restarts) <a class="header-anchor" href="#runtime-settings-persist-across-restarts" aria-label="Permalink to &quot;Runtime settings (persist across restarts)&quot;">​</a></h2><p>Stored in the <code>app_settings</code> KV. Edit via the admin UI in <strong>Settings → ...</strong>.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Where to change</th></tr></thead><tbody><tr><td>Active LLM model</td><td>Language model</td></tr><tr><td>Temperature / Top P / Context window</td><td>Language model → Tuning</td></tr><tr><td>App name, page title, favicon URL</td><td>Branding</td></tr><tr><td>Backup schedule + retention (<code>db_backup_keep</code>, default 7)</td><td>Database</td></tr><tr><td>Cleanup schedule + window (<code>db_cleanup_older_days</code>, default 90)</td><td>Database</td></tr><tr><td>OPML export schedule + retention (<code>opml_keep</code>, default 12)</td><td>Database</td></tr></tbody></table><p>Each user also has client-side preferences stored in browser <code>localStorage</code>:</p><table tabindex="0"><thead><tr><th>Preference</th><th>Default</th><th>Key</th></tr></thead><tbody><tr><td>Theme</td><td>Auto (OS)</td><td><code>ember:theme</code></td></tr><tr><td>Article density</td><td>Cards</td><td><code>ember:density</code></td></tr><tr><td>Sidebar collapsed</td><td>Open</td><td><code>ember:sidebar</code></td></tr><tr><td>AI summary card visible</td><td>On</td><td><code>ember:show-summary</code></td></tr><tr><td>Article images visible</td><td>On</td><td><code>ember:show-images</code></td></tr><tr><td>Summary card collapsed</td><td>Open</td><td><code>ember:summary-collapsed</code></td></tr><tr><td>Scroll-to-mark-read</td><td>On</td><td><code>ember:scroll-mark-read</code></td></tr><tr><td>Custom theme palette</td><td>n/a</td><td><code>ember:custom</code></td></tr></tbody></table><h2 id="hardware-aware-model-recommendation" tabindex="-1">Hardware-aware model recommendation <a class="header-anchor" href="#hardware-aware-model-recommendation" aria-label="Permalink to &quot;Hardware-aware model recommendation&quot;">​</a></h2><p>Run <code>ember probe</code> (or open the admin Language model page) to see a recommendation based on detected RAM, CPU count, and GPU.</p><table tabindex="0"><thead><tr><th>RAM</th><th>GPU</th><th>Recommended</th></tr></thead><tbody><tr><td>&lt; 2 GiB</td><td>—</td><td>Disable summaries</td></tr><tr><td>2–4 GiB</td><td>—</td><td><code>qwen2.5:0.5b</code></td></tr><tr><td>4–8 GiB</td><td>—</td><td><code>qwen2.5:0.5b</code></td></tr><tr><td>8–16 GiB</td><td>—</td><td><code>qwen2.5:1.5b</code></td></tr><tr><td>16 GiB+</td><td>—</td><td><code>qwen2.5:3b</code></td></tr><tr><td>any</td><td>NVIDIA / Apple Silicon</td><td><code>qwen2.5:7b</code></td></tr></tbody></table><h2 id="stack-level-env-vars-docker-compose" tabindex="-1">Stack-level env vars (docker-compose) <a class="header-anchor" href="#stack-level-env-vars-docker-compose" aria-label="Permalink to &quot;Stack-level env vars (docker-compose)&quot;">​</a></h2><p>These configure the bundled <code>deploy/docker-compose.yml</code> stack rather than the Ember binary itself.</p><table tabindex="0"><thead><tr><th>Var</th><th>Default</th><th>Notes</th></tr></thead><tbody><tr><td><code>EMBER_HOSTNAME</code></td><td><code>localhost</code></td><td>Hostname Caddy serves. Real DNS name → automatic Let&#39;s Encrypt.</td></tr><tr><td><code>CADDY_EMAIL</code></td><td><code>admin@localhost</code></td><td>Email for ACME registration.</td></tr><tr><td><code>EMBER_HTTP_PORT</code></td><td><code>80</code></td><td>Host port Caddy publishes for HTTP. Change when 80 is taken locally.</td></tr><tr><td><code>EMBER_HTTPS_PORT</code></td><td><code>443</code></td><td>Host port Caddy publishes for HTTPS. Change when 443 is taken locally.</td></tr></tbody></table><p>If you change the ports, reach the site at the mapped port — e.g. <code>EMBER_HTTPS_PORT=8443</code> → visit <code>https://localhost:8443</code>. Inside the container Caddy still listens on 80/443; only the host-side mapping changes.</p><p><strong>Let&#39;s Encrypt caveat:</strong> automatic-HTTPS via Let&#39;s Encrypt&#39;s HTTP-01 challenge requires the <strong>public</strong> port 80 to be reachable; TLS-ALPN-01 requires public 443. If you remap <em>and</em> expect Let&#39;s Encrypt to issue certs, ensure your public ingress (router / upstream proxy / Cloudflare) still terminates on 80/443 and forwards to your mapped host ports. For homelab use with <code>tls internal</code> in the Caddyfile, any ports work fine.</p><h2 id="reverse-proxy" tabindex="-1">Reverse proxy <a class="header-anchor" href="#reverse-proxy" aria-label="Permalink to &quot;Reverse proxy&quot;">​</a></h2><p>Ember expects TLS to be terminated upstream. The reference <code>Caddyfile</code> in <code>deploy/Caddyfile</code> covers:</p><ul><li>Automatic Let&#39;s Encrypt for a real hostname.</li><li><code>tls internal</code> for self-signed homelab certs.</li><li>Forwarding <code>X-Real-IP</code> (Ember honors this header <strong>only</strong> when the immediate peer is loopback / Docker / LAN).</li></ul><p>If you front Ember with Cloudflare, set the <a href="https://developers.cloudflare.com/ssl/origin-configuration/authenticated-origin-pull/" target="_blank" rel="noreferrer">authenticated origin pull</a> so only Cloudflare can reach your origin.</p>',23)])])}const u=e(a,[["render",c]]);export{p as __pageData,u as default};
